namespace sv_d710f3f13bb94c96b6225272d26f01e7.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service — in Interactive Server mode each circuit gets its own instance,
/// so every user (circuit) has independent theme state.
/// </summary>
public sealed class ThemeService
{
    public Theme Theme { get; private set; } = Theme.System;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChanged;

    public void SetTheme(Theme theme)
    {
        if (Theme == theme) return;
        Theme = theme;
        OnChanged?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        OnChanged?.Invoke();
    }

    public void ApplyAll(Theme theme, string accentColor)
    {
        Theme = theme;
        AccentColor = accentColor;
        OnChanged?.Invoke();
    }
}

// Applies the theme data-attribute to <html> so CSS can respond.
// Persists to localStorage so the choice survives enhanced-nav page swaps.

export function apply(theme, accentColor) {
    document.documentElement.setAttribute("data-theme", theme.toLowerCase());
    document.documentElement.style.setProperty("--accent-color", accentColor);
    localStorage.setItem("theme", theme);
    localStorage.setItem("accentColor", accentColor);
}

export function load() {
    return {
        theme: localStorage.getItem("theme") ?? "System",
        accentColor: localStorage.getItem("accentColor") ?? "#0d6efd"
    };
}

