@using sv_d710f3f13bb94c96b6225272d26f01e7.Services
@rendermode InteractiveServer
@inject ThemeService ThemeSvc
@inject IJSRuntime JS
@implements IDisposable

<span class="theme-indicator" title="Current theme" style="color: @ThemeSvc.AccentColor;">
    @ThemeIcon @ThemeSvc.Theme
</span>

@code {
    private IJSObjectReference? _module;

    private string ThemeIcon => ThemeSvc.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.Light => "☀️",
        _ => "💻"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/theme.js");

        // Hydrate from localStorage on first load
        var stored = await _module.InvokeAsync<ThemeData>("load");
        if (Enum.TryParse<Theme>(stored.Theme, true, out var parsed))
        {
            ThemeSvc.ApplyAll(parsed, stored.AccentColor ?? "#0d6efd");
        }

        // Push current values to DOM
        await _module.InvokeVoidAsync("apply", ThemeSvc.Theme.ToString(), ThemeSvc.AccentColor);
        StateHasChanged();
    }

    protected override void OnInitialized()
    {
        ThemeSvc.OnChanged += HandleThemeChanged;
    }

    private async void HandleThemeChanged()
    {
        await InvokeAsync(async () =>
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync("apply", ThemeSvc.Theme.ToString(), ThemeSvc.AccentColor);
            }
            StateHasChanged();
        });
    }

    public void Dispose()
    {
        ThemeSvc.OnChanged -= HandleThemeChanged;
    }

    private sealed class ThemeData
    {
        public string Theme { get; set; } = "System";
        public string? AccentColor { get; set; }
    }
}

@page "/settings"
@using sv_d710f3f13bb94c96b6225272d26f01e7.Services
@rendermode InteractiveServer
@inject ThemeService ThemeSvc
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label fw-bold">Theme</label>
    <div class="btn-group d-block" role="group">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <button class="btn @(ThemeSvc.Theme == t ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => ThemeSvc.SetTheme(t)">
                @t
            </button>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label fw-bold" for="accent">Accent Color</label>
    <input id="accent" type="color" class="form-control form-control-color"
           value="@ThemeSvc.AccentColor"
           @onchange="OnAccentChanged" />
</div>

<p class="text-muted">
    Changes apply instantly across all components, including the header indicator.
</p>

@code {
    protected override void OnInitialized()
    {
        ThemeSvc.OnChanged += Refresh;
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeSvc.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");
    }

    private void Refresh() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        ThemeSvc.OnChanged -= Refresh;
    }
}

